self.inv(),
            match result {
                Ok(index) => {
                    &&& 0 <= index < self@.num_bits
                    &&& self@.num_bits == old(self)@.num_bits
                    &&& !old(self)@.is_bit_set(index as int)
                    &&& self@.is_bit_set(index as int)
