                    &&& self@.set_bits == old(self)@.set_bits.insert(index as int)
                    &&& self@.usage() == old(self)@.usage() + 1
                },
                Err(_) => {
                    &&& old(self)@.is_full()
                    &&& self@ == old(self)@
                },
