                    &&& old(self)@.all_bits_unset_in_range(
                        start as int,
                        start + (size as int),
                    )
                    // Frame: only the allocated range changed.
                    &&& forall|i: int|
                        0 <= i < self@.num_bits && (i < start || i >= start + (size as int))
                            ==> self@.is_bit_set(i) == old(self)@.is_bit_set(
